using UnityEngine;
using UnityEditor;
using UnityEditor.SceneManagement;
using System.Collections.Generic;

public class Script
{
    public static string Main()
    {
        // ── 1. Remove ALL existing Enemy-tagged objects from scene ───────
        var toDestroy = new List<GameObject>();
        foreach (var go in UnityEngine.Object.FindObjectsByType<GameObject>(FindObjectsSortMode.None))
            if (go.CompareTag("Enemy"))
                toDestroy.Add(go);

        foreach (var go in toDestroy)
            UnityEngine.Object.DestroyImmediate(go);

        // ── 2. Load Enemy prefab ─────────────────────────────────────────
        string prefabPath = "Assets/Prefabs/Enemies/Enemy.prefab";
        var prefab = AssetDatabase.LoadAssetAtPath<GameObject>(prefabPath);
        if (prefab == null)
            return $"ERROR: Enemy prefab not found at {prefabPath}";

        // ── 3. Instantiate 3 enemies at spread-out positions ─────────────
        var positions = new Vector3[]
        {
            new Vector3( 4f, 1f,  4f),
            new Vector3(-4f, 1f,  4f),
            new Vector3( 0f, 1f, -4f),
        };

        for (int i = 0; i < positions.Length; i++)
        {
            var enemy = (GameObject)PrefabUtility.InstantiatePrefab(prefab);
            enemy.transform.position = positions[i];
            enemy.name = $"Enemy_{i + 1}";
        }

        // ── 4. Save scene ────────────────────────────────────────────────
        EditorSceneManager.MarkAllScenesDirty();
        EditorSceneManager.SaveOpenScenes();

        return $"SUCCESS: Removed {toDestroy.Count} old enemies. Placed 3 fresh enemies in scene.";
    }
}
